import { useState, useEffect, useRef, useMemo } from "react";
import "../styles/Stats.css";

export default function Stats() {
  // Memoize the stats array to avoid unnecessary re-creations on each render
  const stats = useMemo(() => [
    { label: "Projects Completed", value: 500 },
    { label: "Clients Served", value: 100 },
    { label: "Years of Experience", value: 2 },
    { label: "Team Members", value: 10 },
  ], []); // Empty dependency array ensures `stats` is only created once

  const [values, setValues] = useState(stats.map(() => 0)); // Initialize values for each stat
  const [inView, setInView] = useState(false); // Track if the section is in view
  const statsSectionRef = useRef(null);

  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            setInView(true); // Set to true when the section is in view
          }
        });
      },
      {
        threshold: 0.5, // Trigger when 50% of the section is visible
      }
    );

    const currentRef = statsSectionRef.current;

    if (currentRef) {
      observer.observe(currentRef);
    }

    return () => {
      if (currentRef) {
        observer.unobserve(currentRef);
      }
    };
  }, []); // Only set up observer once when component mounts

  useEffect(() => {
    if (!inView) return;

    // Set the values to their target when in view
    setValues(stats.map(stat => stat.value));
  }, [inView, stats]); // Only trigger when the section is in view

  return (
    <section ref={statsSectionRef} className="stats-section">
      {stats.map((stat, index) => (
        <div key={index} className="stat-item">
          <h4>{values[index]}+</h4>
          <p>{stat.label}</p>
        </div>
      ))}
    </section>
  );
}
